const e=JSON.parse('{"key":"v-2e6b22bb","path":"/skills/lang/python/decorators.html","title":"修饰符","lang":"zh-CN","frontmatter":{"title":"修饰符","description":"本质是对函数的封装，还是Callable。 函数修饰符 修饰函数或类中的方法，对于类中方法来说，修饰符在类内和类外不影响。 修饰符无参数 1. 被修饰无参数 ```python def decorator(func): def wraper(): print(\\"before\\") func() return wraper @decorator def func(): print(\\"a\\") func() ``` 可以看出还是函数的函数，修饰符的参数为函数名func，用另一个函数wrapper对func进行封装，返回封装的函数wraper。实际上运行的是wraper(). 所以其实没有固定格式。写外边也行。 ```python from typing import * def outside_wraper(func:Callable[[],None]): print(\\"before\\") return func def decorator(func): return outside_wraper(func) @decorator def func(): print(\\"a\\") func() ``` 2. 被修饰有参数 ```python from typing import * def decorator(func): def wraper(*args,**kwargs): print(\\"before\\") func(*args,**kwargs) return wraper @decorator def func(a): print(a) func(1) ```","head":[["meta",{"property":"og:url","content":"https://taochenyue.zone/skills/lang/python/decorators.html"}],["meta",{"property":"og:site_name","content":"TCY"}],["meta",{"property":"og:title","content":"修饰符"}],["meta",{"property":"og:description","content":"本质是对函数的封装，还是Callable。 函数修饰符 修饰函数或类中的方法，对于类中方法来说，修饰符在类内和类外不影响。 修饰符无参数 1. 被修饰无参数 ```python def decorator(func): def wraper(): print(\\"before\\") func() return wraper @decorator def func(): print(\\"a\\") func() ``` 可以看出还是函数的函数，修饰符的参数为函数名func，用另一个函数wrapper对func进行封装，返回封装的函数wraper。实际上运行的是wraper(). 所以其实没有固定格式。写外边也行。 ```python from typing import * def outside_wraper(func:Callable[[],None]): print(\\"before\\") return func def decorator(func): return outside_wraper(func) @decorator def func(): print(\\"a\\") func() ``` 2. 被修饰有参数 ```python from typing import * def decorator(func): def wraper(*args,**kwargs): print(\\"before\\") func(*args,**kwargs) return wraper @decorator def func(a): print(a) func(1) ```"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-10T04:12:46.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-10T04:12:46.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"修饰符\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-03-10T04:12:46.000Z\\",\\"author\\":[]}"]]},"headers":[{"level":2,"title":"函数修饰符","slug":"函数修饰符","link":"#函数修饰符","children":[{"level":3,"title":"修饰符无参数","slug":"修饰符无参数","link":"#修饰符无参数","children":[]}]},{"level":2,"title":"类修饰符","slug":"类修饰符","link":"#类修饰符","children":[]}],"git":{"createdTime":1678421566000,"updatedTime":1678421566000,"contributors":[{"name":"TaoChenyue","email":"3038816978@qq.com","commits":1}]},"readingTime":{"minutes":1.08,"words":324},"filePathRelative":"skills/lang/python/decorators.md","localizedDate":"2023年3月10日","excerpt":"<p>本质是对函数的封装，还是Callable。</p>\\n<h2> 函数修饰符</h2>\\n<p>修饰函数或类中的方法，对于类中方法来说，修饰符在类内和类外不影响。</p>\\n<h3> 修饰符无参数</h3>\\n<pre><code>  1. 被修饰无参数\\n\\n    ```python\\n    def decorator(func):\\n        def wraper():\\n            print(\\"before\\")\\n            func()\\n        return wraper\\n\\n    @decorator\\n    def func():\\n        print(\\"a\\")\\n        \\n    func()\\n    ```\\n    可以看出还是函数的函数，修饰符的参数为函数名func，用另一个函数wrapper对func进行封装，返回封装的函数wraper。实际上运行的是wraper(). 所以其实没有固定格式。写外边也行。\\n\\n    ```python\\n    from typing import *\\n    def outside_wraper(func:Callable[[],None]):\\n        print(\\"before\\")\\n        return func\\n        \\n    def decorator(func):\\n        return outside_wraper(func)\\n\\n    @decorator\\n    def func():\\n        print(\\"a\\")\\n        \\n    func()\\n    ```\\n\\n  2. 被修饰有参数\\n\\n    ```python\\n    from typing import *\\n        \\n    def decorator(func):\\n        def wraper(*args,**kwargs):\\n            print(\\"before\\")\\n            func(*args,**kwargs)\\n        return wraper\\n\\n    @decorator\\n    def func(a):\\n        print(a)\\n        \\n    func(1)\\n    ```\\n</code></pre>","autoDesc":true}');export{e as data};
